  Future<Map<String, dynamic>> _analyzeWithVision(File file) async {
    final bytes = await file.readAsBytes();
    final base64Image = base64Encode(bytes);

    final url = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$googleApiKey');

    final body = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 5},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 5},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 1},
          ],
        }
      ]
    };

    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(body),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('Vision API error ${response.statusCode}: ${response.body}');
    }

    return jsonDecode(response.body) as Map<String, dynamic>;
